const ASSEMBLY_IMAGES = {
  CC_T10: "data:image/png;base64,",
  CC_T20: "data:image/png;base64,",
  SP_T31: "data:image/png;base64,",
  SP_T35: "data:image/png;base64,",
};

// Helper: returns the right image key for the current configuration
function getAssemblyImage(style, coverStyle, spacerStyle) {
  if (style === 'Close-Coupled') {
    return coverStyle === 'T20' ? ASSEMBLY_IMAGES.CC_T20 : ASSEMBLY_IMAGES.CC_T10;
  } else {
    return spacerStyle === 'T35' ? ASSEMBLY_IMAGES.SP_T35 : ASSEMBLY_IMAGES.SP_T31;
  }
}

