// ===================== STATE =====================
let state = {
  style: 'Close-Coupled',
  spacerStyle: 'T35',
  dbseMode: 'stock',
};

// ===================== SIZE FILTERING =====================
function updateAvailableSizes() {
  const sel = document.getElementById('size-select');
  const currentValue = sel.value;
  sel.innerHTML = '<option value="">— select size —</option>';

  const shaft1 = parseFloat(document.getElementById('shaft1').value) || 0;
  const shaft2 = parseFloat(document.getElementById('shaft2').value) || 0;
  const torque = parseFloat(document.getElementById('torque').value) || 0;
  const sf = parseFloat((document.getElementById('sf-btn-app').classList.contains('active') ? document.getElementById('sf-hidden') : document.getElementById('sf')).value) || 1;
  const speed = parseFloat(document.getElementById('speed').value) || 0;
  const designTorque = torque * sf;
  const filterActive = shaft1 > 0 || shaft2 > 0 || torque > 0 || speed > 0;

  let compatible = [];

  if (state.style === 'Close-Coupled') {
    compatible = ccData.filter(row => {
      if (!filterActive) return true;
      const largeShaft = Math.max(shaft1, shaft2);
      if (largeShaft > 0 && row.maxBore < largeShaft) return false;
      if (torque > 0 && row.maxTorque < designTorque) return false;
      if (speed > 0 && row.maxRPM < speed) return false;
      return true;
    }).map(row => row.size);
  } else {
    compatible = spacerData.filter(row => {
      if (row.spacerStyle !== state.spacerStyle) return false;
      if (!filterActive) return true;
      if (torque > 0 && row.maxTorque < designTorque) return false;
      if (speed > 0 && row.maxRPM < speed) return false;
      if (shaft1 > 0 || shaft2 > 0) {
        const s1 = shaft1, s2 = shaft2;
        const fit1 = (!s1 || (s1 >= row.minBore1 && s1 <= row.maxBore1)) &&
                     (!s2 || (s2 >= row.minBore2 && s2 <= row.maxBore2));
        const fit2 = (!s2 || (s2 >= row.minBore1 && s2 <= row.maxBore1)) &&
                     (!s1 || (s1 >= row.minBore2 && s1 <= row.maxBore2));
        if (!fit1 && !fit2) return false;
      }
      return true;
    }).map(row => row.size);
  }

  compatible = [...new Set(compatible)].sort((a, b) => parseInt(a) - parseInt(b));

  compatible.forEach(size => {
    const opt = document.createElement('option');
    opt.value = size;
    opt.textContent = size;
    if (size === currentValue) opt.selected = true;
    sel.appendChild(opt);
  });

  if (currentValue && !compatible.includes(currentValue)) sel.value = '';
}

// ===================== INIT =====================
function init() {
  document.getElementById('martin-logo').src = 'martin_logo.png';
  document.getElementById('tab-blueflex').addEventListener('click', () => switchTab('blueflex'));
  document.getElementById('tab-goflex').addEventListener('click', () => switchTab('goflex'));
  document.getElementById('tab-gear').addEventListener('click', () => switchTab('gear'));
  sfInit('', 'blueflex');
  updateAvailableSizes();
  setupEventListeners();
  compute();
}

function calcTorque() {
  const hp    = parseFloat(document.getElementById('hp').value) || 0;
  const speed = parseFloat(document.getElementById('speed').value) || 0;
  const display     = document.getElementById('torque-display');
  const torqueInput = document.getElementById('torque');
  if (hp > 0 && speed > 0) {
    const t = Math.round((hp * 63025) / speed);
    torqueInput.value = t;
    display.textContent = t.toLocaleString();
    display.className = 'sf-value-display ok';
  } else {
    torqueInput.value = 0;
    display.textContent = '—';
    display.className = 'sf-value-display dim';
  }
  updateAvailableSizes();
  compute();
}

function setupEventListeners() {
  document.getElementById('btn-cc').addEventListener('click', () => setStyle('Close-Coupled'));
  document.getElementById('btn-sp').addEventListener('click', () => setStyle('Spacer'));
  document.getElementById('btn-t35').addEventListener('click', () => setSpacerStyle('T35'));
  document.getElementById('btn-t31').addEventListener('click', () => setSpacerStyle('T31'));
  document.getElementById('btn-dbse-stock').addEventListener('click', () => setDbseMode('stock'));
  document.getElementById('btn-dbse-custom').addEventListener('click', () => setDbseMode('custom'));

  ['shaft1','shaft2','torque','sf','sf-hidden','speed'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.addEventListener('input', () => { updateAvailableSizes(); compute(); });
  });

  document.getElementById('hp').addEventListener('input', calcTorque);
  document.getElementById('speed').addEventListener('input', calcTorque);

  ['size-select','cover-select','stock-dbse-select','custom-dbse'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.addEventListener('change', compute);
  });
}

// ===================== UI FUNCTIONS =====================
function setStyle(s) {
  state.style = s;
  document.getElementById('btn-cc').classList.toggle('active', s === 'Close-Coupled');
  document.getElementById('btn-sp').classList.toggle('active', s === 'Spacer');
  document.getElementById('spacer-style-group').style.display = s === 'Spacer' ? '' : 'none';
  document.getElementById('cover-style-group').style.display = s === 'Close-Coupled' ? '' : 'none';
  document.getElementById('dbse-group').style.display = s === 'Spacer' ? '' : 'none';
  updateAvailableSizes();
  compute();
}

function setSpacerStyle(s) {
  state.spacerStyle = s;
  document.getElementById('btn-t35').classList.toggle('active', s === 'T35');
  document.getElementById('btn-t31').classList.toggle('active', s === 'T31');
  updateStockDBSEOptions();
  updateAvailableSizes();
  compute();
}

function setDbseMode(m) {
  state.dbseMode = m;
  document.getElementById('btn-dbse-stock').classList.toggle('active', m === 'stock');
  document.getElementById('btn-dbse-custom').classList.toggle('active', m === 'custom');
  document.getElementById('stock-dbse-group').style.display = m === 'stock' ? '' : 'none';
  document.getElementById('custom-dbse-group').style.display = m === 'custom' ? '' : 'none';
  compute();
}

function updateStockDBSEOptions() {
  const size = document.getElementById('size-select').value;
  const sel = document.getElementById('stock-dbse-select');
  const cur = sel.value;
  sel.innerHTML = '<option value="">— select DBSE —</option>';
  if (!size) return;
  const key = size + '-' + state.spacerStyle;
  const vals = stockDBSE[key] || [];
  vals.forEach(v => {
    const o = document.createElement('option');
    o.value = v;
    o.textContent = Number(v).toFixed(4) + ' in';
    if (String(v) === cur) o.selected = true;
    sel.appendChild(o);
  });
}

function calcSpacerCL(size, spacerStyle, dbse) {
  const dim = spacerDims[size];
  if (!dim || dbse == null) return null;

  const sizeNum = parseInt(size.replace('T', ''));
  const E = dim.E;
  const U = dim.U;
  const gapFull = dim.t31Gap;  // T31 gap
  const gapHalf = dim.t35Gap;  // T35 gap

  // Determine range based on size number
  const range = sizeNum <= 1140 ? 'STD' : sizeNum <= 1170 ? 'HD1' : 'HD2';

  let cl;
  if (range === 'STD') {
    cl = spacerStyle === 'T31'
      ? (dbse - 2 * E - gapFull) / 2
      : dbse - (E + gapHalf);
  } else if (range === 'HD1') {
    cl = spacerStyle === 'T31'
      ? ((dbse - gapFull) / 2) - E
      : dbse - gapHalf - E;
  } else { // HD2
    cl = spacerStyle === 'T31'
      ? ((dbse - gapFull) / 2) - U
      : dbse - gapHalf - U;
  }

  return Math.round(cl * 10000) / 10000;
}

function calcSpacerOAL(size, spacerStyle, dbse) {
  const dim = spacerDims[size];
  if (!dim || dbse == null) return null;

  const sizeNum = parseInt(size.replace('T', ''));
  const E = dim.E;
  const U = dim.U;
  const range = sizeNum <= 1140 ? 'STD' : sizeNum <= 1170 ? 'HD1' : 'HD2';
  const cl = calcSpacerCL(size, spacerStyle, dbse);
  if (cl == null) return null;

  let oal;
  if (range === 'STD')      oal = cl + U;
  else if (range === 'HD1') oal = cl + 0.12;
  else                      oal = cl + (U - E);

  return Math.round(oal * 10000) / 10000;
}

function fmtCL(cl) {
  if (cl == null) return 'X.XXXX';
  return cl.toFixed(4).replace(/\.?0+$/, '');
}

// ===================== RENDER HELPERS =====================
function renderErrors(msgs) {
  document.getElementById('output-content').innerHTML =
    msgs.map(m => `<div class="err-block">⚠ ${m}</div>`).join('');
}

function bomRow(qty, itemId, desc, indent = false) {
  return `<tr${indent ? ' class="sub-row"' : ''}>
    <td class="qty${indent ? ' indent' : ''}">${qty}</td>
    <td class="item-id${indent ? ' indent' : ''}">${itemId}</td>
    <td class="${indent ? 'indent' : ''}">${desc}</td>
  </tr>`;
}

// ===================== RENDER: CLOSE COUPLED =====================
function renderCCOutput(row, s1, s2, torque, sf, designTorque, speed, errors, warnings) {
  const comp = compData[row.size];
  if (!comp) return;

  const dsf = row.maxTorque / (torque || 1);
  const dsfOk = dsf >= sf;
  const stdHub1ID = s1 ? `${comp.stdHub} ${s1}` : comp.stdHub;
  const stdHub2ID = s2 ? `${comp.stdHub} ${s2}` : comp.stdHub;
  const assemblyName = `${row.size}-${row.coverStyle}`;

  let html = '';
  html += `<div class="assembly-image-wrap"><img src="${getAssemblyImage('Close-Coupled', row.coverStyle, null)}" class="assembly-image" alt="Assembly diagram"></div>`;
  if (errors.length) html += errors.map(e => `<div class="alert err">⚠ ${e}</div>`).join('');
  if (warnings.length) html += warnings.map(w => `<div class="alert warn">⚠ ${w}</div>`).join('');

  html += `
  <div class="output-header">
    <div>
      <div class="assembly-name-display">${assemblyName}</div>
      <div class="description-tag">Close Coupled Assembly</div>
    </div>
  </div>
  <div class="specs-bar">
    <div class="spec-item"><div class="spec-label">Max Torque</div><div class="spec-value accent">${row.maxTorque.toLocaleString()}</div><div class="spec-unit">in-lbs</div></div>
    <div class="spec-item"><div class="spec-label">Max Speed</div><div class="spec-value">${row.maxRPM.toLocaleString()}</div><div class="spec-unit">RPM</div></div>
    <div class="spec-item"><div class="spec-label">Design SF</div><div class="spec-value ${torque ? (dsfOk ? 'ok' : 'err') : ''}">${torque ? dsf.toFixed(2) : '—'}</div></div>
    <div class="spec-item"><div class="spec-label">Cover Style</div><div class="spec-value">${row.coverStyle}</div></div>
  </div>
  <div class="bom-section">
    <div class="bom-title">Bill of Materials</div>
    <table class="bom-table">
      <thead><tr><th>QTY</th><th>Item ID</th><th>Description</th></tr></thead>
      <tbody>
        ${bomRow(1, comp.t10Cov, 'Cover')}
        ${bomRow(1, stdHub1ID, s1 ? `Standard Hub 1 (${s1} in)` : 'Standard Hub 1')}
        ${bomRow(1, stdHub2ID, s2 ? `Standard Hub 2 (${s2} in)` : 'Standard Hub 2')}
        ${bomRow(1, comp.subasy, 'Subassembly')}
      </tbody>
    </table>
  </div>`;

  document.getElementById('output-content').innerHTML = html;
}

// ===================== RENDER: SPACER =====================
function renderSpacerOutput(row, s1, s2, torque, sf, designTorque, speed, dbse, errors, warnings) {
  const comp = compData[row.size];
  if (!comp) return;

  const dsf = row.maxTorque / (torque || 1);
  const dsfOk = dsf >= sf;
  const isStock = state.dbseMode === 'stock';
  const descTag = state.spacerStyle === 'T35' ? 'T35 Half Spacer Assembly' : 'T31 Full Spacer Assembly';

  const assemblyName = dbse !== null ? `${row.size}-${state.spacerStyle}-${dbse}` : `${row.size}-${state.spacerStyle}`;

  const sh1ID = s1 ? `${comp.shHub} ${s1}` : comp.shHub;
  const sh2ID = s2 ? `${comp.shHub} ${s2}` : comp.shHub;

  // T35 Half: shaft hub on larger shaft side, standard hub on smaller side
  const largerShaft  = (s1 || 0) >= (s2 || 0) ? s1 : s2;
  const smallerShaft = (s1 || 0) >= (s2 || 0) ? s2 : s1;
  const t35ShaftHubID = largerShaft  ? `${comp.shHub} ${largerShaft}`  : comp.shHub;
  const t35StdHubID   = smallerShaft ? `${comp.stdHub} ${smallerShaft}` : comp.stdHub;

  const subasyID = `${row.size}10-SUBASY`;

  // Determine spacer part IDs — stock lookup vs calculated
  let spacer1ID, spacer2ID, hub1ID, hub2ID, spacerCL = null, spacerOALDisplay = null;

  if (isStock && dbse !== null) {
    // Build lookup key matching the table: e.g. "1090T-T31-10"
    // The keys use the raw DBSE number as stored — try exact float key first
    const key = `${row.size}-${state.spacerStyle}-${dbse}`;
    const entry = sizeStyleDBSE[key];
    if (entry) {
      spacer1ID = entry.spacer1;
      spacer2ID = entry.spacer2;
      hub1ID    = entry.hub1;
      hub2ID    = entry.hub2;
    } else {
      // Fallback: try rounding key variations
      const keyRound = `${row.size}-${state.spacerStyle}-${parseFloat(dbse.toFixed(4))}`;
      const entryR = sizeStyleDBSE[keyRound];
      spacer1ID = entryR ? entryR.spacer1 : 'LOOKUP ERROR';
      spacer2ID = entryR ? entryR.spacer2 : 'NA';
      hub1ID    = entryR ? entryR.hub1    : 'LOOKUP ERROR';
      hub2ID    = entryR ? entryR.hub2    : 'NA';
    }
  } else if (dbse !== null) {
    // Custom DBSE — calculate CL and build part IDs
    spacerCL = calcSpacerCL(row.size, state.spacerStyle, dbse);
    const spacerOAL = calcSpacerOAL(row.size, state.spacerStyle, dbse);
    const clStr = fmtCL(spacerCL);
    spacer1ID = spacerCL !== null ? `${row.size}-CL${clStr}` : 'N/A';
    spacer2ID = spacer1ID;
    hub1ID    = spacerCL !== null ? `${comp.spcrHub}${clStr}` : 'N/A';
    hub2ID    = hub1ID;
    spacerOALDisplay = spacerOAL; // store for display in specs bar
  } else {
    spacer1ID = 'N/A'; spacer2ID = 'N/A'; hub1ID = 'N/A'; hub2ID = 'N/A';
  }

  let html = '';
  html += `<div class="assembly-image-wrap"><img src="${getAssemblyImage('Spacer', null, state.spacerStyle)}" class="assembly-image" alt="Assembly diagram"></div>`;
  if (errors.length) html += errors.map(e => `<div class="alert err">⚠ ${e}</div>`).join('');
  if (warnings.length) html += warnings.map(w => `<div class="alert warn">⚠ ${w}</div>`).join('');

  html += `
  <div class="output-header">
    <div>
      <div class="assembly-name-display">${assemblyName}</div>
      <div class="description-tag">${descTag}</div>
    </div>
  </div>
  <div class="specs-bar">
    <div class="spec-item"><div class="spec-label">Max Torque</div><div class="spec-value accent">${row.maxTorque.toLocaleString()}</div><div class="spec-unit">in-lbs</div></div>
    <div class="spec-item"><div class="spec-label">Max Speed</div><div class="spec-value">${row.maxRPM.toLocaleString()}</div><div class="spec-unit">RPM</div></div>
    <div class="spec-item"><div class="spec-label">Design SF</div><div class="spec-value ${torque ? (dsfOk ? 'ok' : 'err') : ''}">${torque ? dsf.toFixed(2) : '—'}</div></div>
    <div class="spec-item"><div class="spec-label">DBSE Range</div><div class="spec-value" style="font-size:13px">${row.minDBSE} – ${row.maxDBSE}</div><div class="spec-unit">in</div></div>
    ${spacerCL !== null ? `<div class="spec-item"><div class="spec-label">Spacer CL</div><div class="spec-value accent">${spacerCL.toFixed(4)}</div><div class="spec-unit">in</div></div>` : ''}
	${spacerOALDisplay !== null ? `<div class="spec-item"><div class="spec-label">Spacer OAL</div><div class="spec-value accent">${spacerOALDisplay.toFixed(4)}</div><div class="spec-unit">in</div></div>` : ''}
  </div>
  <div class="bom-section">
    <div class="bom-title">Bill of Materials</div>
    <table class="bom-table">
      <thead><tr><th>QTY</th><th>Item ID</th><th>Description</th></tr></thead>
      <tbody>
        ${state.spacerStyle === 'T35'
          ? bomRow(1, t35ShaftHubID, largerShaft  ? `Shaft Hub (${largerShaft} in)`   : 'Shaft Hub')
          : bomRow(1, sh1ID,         s1            ? `Shaft Hub 1 (${s1} in)`          : 'Shaft Hub 1')}
        ${state.spacerStyle === 'T35'
          ? bomRow(1, t35StdHubID,   smallerShaft  ? `Standard Hub (${smallerShaft} in)` : 'Standard Hub')
          : bomRow(1, sh2ID,         s2             ? `Shaft Hub 2 (${s2} in)`           : 'Shaft Hub 2')}`;

  if (state.spacerStyle === 'T35') {
    html += `
        ${bomRow(1, spacer1ID, 'Spacer (Half)')}
        ${bomRow(1, hub1ID, 'Spacer Hub (SPCRHUB)', true)}
        ${bomRow(1, comp.teethRing, 'Teeth Ring', true)}
        ${bomRow(comp.setscrewQty, comp.setscrewDesc, 'Setscrews', true)}
        ${bomRow(1, comp.hwKit, 'Fastener Kit', true)}
        ${bomRow(1, subasyID, 'Subassembly')}`;
  } else {
    html += `
        ${bomRow(1, spacer1ID, 'Spacer 1')}
        ${bomRow(1, hub1ID, 'Spacer Hub (SPCRHUB)', true)}
        ${bomRow(1, comp.teethRing, 'Teeth Ring', true)}
        ${bomRow(comp.setscrewQty, comp.setscrewDesc, 'Setscrews', true)}
        ${bomRow(1, comp.hwKit, 'Fastener Kit', true)}
        ${bomRow(1, spacer2ID, 'Spacer 2')}
        ${bomRow(1, hub2ID, 'Spacer Hub (SPCRHUB)', true)}
        ${bomRow(1, comp.teethRing, 'Teeth Ring', true)}
        ${bomRow(comp.setscrewQty, comp.setscrewDesc, 'Setscrews', true)}
        ${bomRow(1, comp.hwKit, 'Fastener Kit', true)}
        ${bomRow(1, subasyID, 'Subassembly')}`;
  }

  html += `</tbody></table></div>`;
  document.getElementById('output-content').innerHTML = html;
}

// ===================== MAIN COMPUTE =====================
function compute() {
  const shaft1 = parseFloat(document.getElementById('shaft1').value) || 0;
  const shaft2 = parseFloat(document.getElementById('shaft2').value) || 0;
  const torque = parseFloat(document.getElementById('torque').value) || 0;
  const sf = parseFloat((document.getElementById('sf-btn-app').classList.contains('active') ? document.getElementById('sf-hidden') : document.getElementById('sf')).value) || 1;
  const speed = parseFloat(document.getElementById('speed').value) || 0;
  const size = document.getElementById('size-select').value;
  const cover = document.getElementById('cover-select').value;

  updateStockDBSEOptions();

  if (size && state.style === 'Spacer') {
    const row = spacerData.find(r => r.size === size && r.spacerStyle === state.spacerStyle);
    if (row) {
      document.getElementById('dbse-range-txt').innerHTML =
        `Range: <span>${row.minDBSE}</span> – <span>${row.maxDBSE}</span> in`;
    }
  }

  if (!shaft1 && !shaft2 && !torque) {
    document.getElementById('output-content').innerHTML =
      `<div class="placeholder"><div class="placeholder-icon">⚙</div><p>Enter inputs to configure assembly</p></div>`;
    return;
  }

  const designTorque = torque * sf;
  const errors = [];
  const warnings = [];

  let dbse = null;
  if (state.style === 'Spacer' && state.dbseMode !== 'na') {
    dbse = state.dbseMode === 'stock'
      ? parseFloat(document.getElementById('stock-dbse-select').value) || null
      : parseFloat(document.getElementById('custom-dbse').value) || null;
  }

  if (state.style === 'Close-Coupled') {
    if (!size) return renderErrors(['Select a coupling size to proceed.']);
    if (!cover) return renderErrors(['Select a cover style to proceed.']);
    const row = ccData.find(r => r.size === size && r.coverStyle === cover);
    if (!row) return renderErrors(['No data found for selected size/cover combination.']);

    const largeShaft = Math.max(shaft1, shaft2);
    if (largeShaft > 0 && largeShaft < row.minBore) warnings.push(`Shaft size (${largeShaft}") is below minimum bore (${row.minBore}")`);
    if (shaft1 > row.maxBore) errors.push(`Shaft 1 (${shaft1}") exceeds max bore (${row.maxBore}")`);
    if (shaft2 > row.maxBore) errors.push(`Shaft 2 (${shaft2}") exceeds max bore (${row.maxBore}")`);
    if (torque > 0 && designTorque > row.maxTorque) errors.push(`Design torque (${designTorque.toFixed(0)} in-lbs) exceeds max torque (${row.maxTorque.toLocaleString()} in-lbs)`);
    if (speed > row.maxRPM) errors.push(`Speed (${speed} RPM) exceeds max speed (${row.maxRPM} RPM)`);

    renderCCOutput(row, shaft1, shaft2, torque, sf, designTorque, speed, errors, warnings);
  } else {
    if (!size) return renderErrors(['Select a coupling size to proceed.']);
    const row = spacerData.find(r => r.size === size && r.spacerStyle === state.spacerStyle);
    if (!row) return renderErrors(['No data found for selected size/spacer style.']);

    if (shaft1 > 0 && shaft1 < row.minBore1) warnings.push(`Shaft 1 (${shaft1}") below min bore 1 (${row.minBore1}")`);
    if (shaft1 > row.maxBore1) errors.push(`Shaft 1 (${shaft1}") exceeds max bore 1 (${row.maxBore1}")`);
    if (shaft2 > 0 && shaft2 < row.minBore2) warnings.push(`Shaft 2 (${shaft2}") below min bore 2 (${row.minBore2}")`);
    if (shaft2 > row.maxBore2) errors.push(`Shaft 2 (${shaft2}") exceeds max bore 2 (${row.maxBore2}")`);
    if (torque > 0 && designTorque > row.maxTorque) errors.push(`Design torque (${designTorque.toFixed(0)} in-lbs) exceeds max torque (${row.maxTorque.toLocaleString()} in-lbs)`);
    if (speed > row.maxRPM) errors.push(`Speed (${speed} RPM) exceeds max speed (${row.maxRPM} RPM)`);
    if (dbse !== null) {
      if (dbse < row.minDBSE) errors.push(`DBSE (${dbse}") is below minimum (${row.minDBSE}")`);
      if (dbse > row.maxDBSE) errors.push(`DBSE (${dbse}") exceeds maximum (${row.maxDBSE}")`);
    }

    renderSpacerOutput(row, shaft1, shaft2, torque, sf, designTorque, speed, dbse, errors, warnings);
  }
}
function switchTab(tab) {
  const tabs = ['blueflex', 'goflex', 'gear'];
  tabs.forEach(t => {
    document.getElementById(`tab-${t}-content`).style.display = t === tab ? 'block' : 'none';
    document.getElementById(`tab-${t}`).classList.toggle('active', t === tab);
  });
  const badges = {
    'blueflex': 'COUPLING TYPE: BLUEFLEX',
    'goflex':   'COUPLING TYPE: GO-FLEX',
    'gear':     'COUPLING TYPE: GEAR',
  };
  document.getElementById('header-badge').textContent = badges[tab];
  if (tab === 'goflex') { gfInitialized = false; gfInit(); }
  if (tab === 'gear')   gcInit();
}

init();
